previewCss:
.darma-loader-darma-custom-762 {
  color: var(--loader-color, #6366f1);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
color: currentColor;
width: 6px;
aspect-ratio: 1;
border-radius: 50%;
animation:
darma-loader-darma-custom-762-l37-1 .75s infinite linear alternate,
darma-loader-darma-custom-762-l37-2 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-762-l37-1 {
0%,
20% {box-shadow:30px 0 0 3px, 10px 0 0 3px, -10px 0 0 3px,-30px 0 0 3px}
60%,
100% {box-shadow:12px 0 0 3px, 14px 0 0 6px, -14px 0 0 6px,-12px 0 0 3px}
}

@keyframes darma-loader-darma-custom-762-l37-2 {
0%,25% {transform: rotate(0)}
50%,100% {transform: rotate(.5turn)}
}

